noncompliant:
// Noncompliant: lowercase enum values
enum SomeEnumeration {
    some,  // Non-Compliant - should be uppercase
    another_value,  // Non-Compliant - snake_case
    mixedCase  // Non-Compliant - camelCase
};

// Noncompliant: inconsistent naming
enum Status {
    active,  // lowercase
    INACTIVE,  // uppercase
    Pending  // PascalCase
};

compliant:
// Compliant: consistent uppercase naming
enum SomeEnumeration {
    SOME,
    ANOTHER_VALUE,
    MIXED_CASE
};

// Compliant: all uppercase with underscores
enum Status {
    ACTIVE,
    INACTIVE,
    PENDING
};

// Compliant: consistent naming pattern
enum FileMode {
    READ_ONLY,
    WRITE_ONLY,
    READ_WRITE
};
